#!/usr/bin/env python3
import os, socket, subprocess, tempfile, time, random, shutil, signal, sys

ROOT = '/workspace/valkey'
SERVER = os.path.join(ROOT, 'src/valkey-server')

def encode_command(*parts):
    out = [f'*{len(parts)}\r\n'.encode()]
    for p in parts:
        if not isinstance(p, (bytes, bytearray)):
            p = str(p).encode()
        out.append(b'$%d\r\n' % len(p))
        out.append(p + b'\r\n')
    return b''.join(out)

class Client:
    def __init__(self, port):
        self.sock = socket.create_connection(('127.0.0.1', port), timeout=5)
        self.file = self.sock.makefile('rb')
    def close(self):
        try: self.file.close(); self.sock.close()
        except Exception: pass
    def call(self, *parts):
        self.sock.sendall(encode_command(*parts))
        return self._read()
    def pipeline(self, commands, chunk=512):
        pending = 0
        buf = []
        for cmd in commands:
            buf.append(encode_command(*cmd)); pending += 1
            if pending >= chunk:
                self.sock.sendall(b''.join(buf)); buf.clear()
                for _ in range(pending): self._read()
                pending = 0
        if pending:
            self.sock.sendall(b''.join(buf))
            for _ in range(pending): self._read()
    def _read(self):
        line = self.file.readline()
        if not line: raise RuntimeError('connection closed')
        prefix = line[:1]
        payload = line[1:-2]
        if prefix == b'+': return payload.decode()
        if prefix == b'-': raise RuntimeError(payload.decode(errors='replace'))
        if prefix == b':': return int(payload)
        if prefix == b'$':
            n = int(payload)
            if n == -1: return None
            data = self.file.read(n); self.file.read(2); return data
        if prefix == b'*':
            n = int(payload)
            if n == -1: return None
            return [self._read() for _ in range(n)]
        raise RuntimeError(f'bad RESP: {line!r}')

def info_value(info, key):
    if isinstance(info, bytes): info = info.decode()
    for line in info.splitlines():
        if line.startswith(key + ':'):
            return line.split(':', 1)[1]
