        # Starve timers while defrag is active. Current code compensates by doing one long defrag slice.
        for _ in range(3):
            try:
                c.call('DEBUG', 'SLEEP', '0.03')
            except RuntimeError as e:
                print('DEBUG SLEEP failed:', e, flush=True)
            time.sleep(0.05)
        max_ms, latest = max_active_defrag_latency(c)
        print('LATENCY LATEST:', latest, flush=True)
        print('MAX_ACTIVE_DEFRAG_CYCLE_MS=%d' % max_ms, flush=True)
        c.call('SHUTDOWN', 'NOSAVE')
        c.close()
        proc.wait(timeout=5)
        return 0 if max_ms >= 5 else 2
    finally:
        if proc.poll() is None:
            proc.terminate()
            try: proc.wait(timeout=3)
            except subprocess.TimeoutExpired: proc.kill(); proc.wait()
        shutil.rmtree(tmp, ignore_errors=True)
if __name__ == '__main__':
    sys.exit(main())
