  1081	        long waitedUs = getMonotonicUs() - defrag.timeproc_end_time;
  1082	        /* Given the elapsed wait time between calls, compute the necessary duty time needed to
  1083	         *  achieve the desired CPU percentage.
  1084	         *  With:  D = duty time, W = wait time, P = percent
  1085	         *  Solve:    D          P
  1086	         *          -----   =  -----
  1087	         *          D + W       100
  1088	         *  Solving for D:
  1089	         *     D = P * W / (100 - P)
  1090	         *
  1091	         * For regular timer invocations, limit the wait time used for this calculation so
  1092	         * starvation recovery does not turn one delayed timer into a long defrag invocation.
  1093	         * Longer waits are treated as time when defrag was effectively paused; the next timer
  1094	         * invocation should still be bounded by the configured active-defrag-cycle-us latency
  1095	         * budget. While blocked, timers are not running at all, so allow catch-up work there. */
  1096	        if (!allow_long_cycle) {
  1097	            long maxWaitedUs = server.active_defrag_cycle_us * (100 - targetCpuPercent) / targetCpuPercent;
  1098	            if (waitedUs > maxWaitedUs) waitedUs = maxWaitedUs;
  1099	        }
  1100	        dutyCycleUs = targetCpuPercent * waitedUs / (100 - targetCpuPercent);
  1101	
  1102	        // Also adjust for any accumulated overage.
  1103	        dutyCycleUs -= defrag.timeproc_overage_us;
  1104	        defrag.timeproc_overage_us = 0;
  1105	
  1106	        if (dutyCycleUs < server.active_defrag_cycle_us) {
  1107	            /* We never reduce our cycle time, that would increase overhead.  Instead, we track this
  1108	             *  as part of the overage, and increase wait time between cycles. */
  1109	            defrag.timeproc_overage_us = server.active_defrag_cycle_us - dutyCycleUs;
  1110	            dutyCycleUs = server.active_defrag_cycle_us;
  1111	        }
  1112	    }
  1113	    return dutyCycleUs;
  1114	}
  1115	
  1116	
  1117	/* Must be called at the end of the timeProc as it records the timeproc_end_time for use in the next
  1118	 * computeDefragCycleUs computation. */
  1119	static int computeDelayMs(monotime intendedEndtime) {
  1120	    defrag.timeproc_end_time = getMonotonicUs();
  1121	    long overage = defrag.timeproc_end_time - intendedEndtime;
  1122	    defrag.timeproc_overage_us += overage; // track over/under desired CPU
  1123	    /* Allow negative overage (underage) to count against existing overage, but don't allow
  1124	     * underage (from short stages) to be accumulated.  */
  1125	    if (defrag.timeproc_overage_us < 0) defrag.timeproc_overage_us = 0;
  1126	
  1127	    int targetCpuPercent = server.active_defrag_cpu_percent;
  1128	    serverAssert(targetCpuPercent > 0 && targetCpuPercent < 100);
  1129	
  1130	    // Given the desired duty cycle, what inter-cycle delay do we need to achieve that?
  1131	    // We want to achieve a specific CPU percent.  To do that, we can't use a skewed computation.
  1132	    // Example, if we run for 1ms and delay 10ms, that's NOT 10%, because the total cycle time is 11ms.
  1133	    // Instead, if we rum for 1ms, our total time should be 10ms.  So the delay is only 9ms.
  1134	    long totalCycleTimeUs = server.active_defrag_cycle_us * 100 / targetCpuPercent;
  1135	    long delayUs = totalCycleTimeUs - server.active_defrag_cycle_us;
  1136	    // Only increase delay by the fraction of the overage that would be non-duty-cycle
  1137	    delayUs += defrag.timeproc_overage_us * (100 - targetCpuPercent) / 100;
  1138	    if (delayUs < 0) delayUs = 0;
  1139	    long delayMs = delayUs / 1000; // round down
  1140	    return delayMs;
  1141	}
  1142	
  1143	
  1144	/* An independent time proc for defrag.  While defrag is running, this is called much more often
  1145	 *  than the server cron.  Frequent short calls provides low latency impact. */
  1146	static long long activeDefragTimeProc(struct aeEventLoop *eventLoop, long long id, void *clientData) {
  1147	    UNUSED(eventLoop);
  1148	    UNUSED(id);
  1149	    UNUSED(clientData);
  1150	
  1151	    // This timer shouldn't be registered unless there's work to do.
  1152	    serverAssert(defrag.current_stage || listLength(defrag.remaining_stages) > 0);
  1153	
  1154	    if (!server.active_defrag_enabled) {
  1155	        // Defrag has been disabled while running
  1156	        endDefragCycle(false);
  1157	        return AE_NOMORE;
  1158	    }
  1159	
  1160	    if (hasActiveChildProcess()) {
  1161	        // If there's a child process, pause the defrag, polling until the child completes.
  1162	        defrag.timeproc_end_time = 0; // prevent starvation recovery
  1163	        return 100;
  1164	    }
  1165	
  1166	    monotime starttime = getMonotonicUs();
  1167	    bool allow_long_cycle = (clientData != NULL);
  1168	    int dutyCycleUs = computeDefragCycleUs(allow_long_cycle);
  1169	    monotime endtime = starttime + dutyCycleUs;
  1170	    bool haveMoreWork = true;
  1171	
  1172	    mstime_t latency;
  1173	    latencyStartMonitor(latency);
  1174	
  1175	    do {
  1176	        if (!defrag.current_stage) {
  1177	            defrag.current_stage = listNodeValue(listFirst(defrag.remaining_stages));
  1178	            listDelNode(defrag.remaining_stages, listFirst(defrag.remaining_stages));
  1179	            // Initialize the stage with endtime==0
  1180	            doneStatus status = defrag.current_stage->stage_fn(0, defrag.current_stage->target, defrag.current_stage->privdata);
  1181	            serverAssert(status == DEFRAG_NOT_DONE); // Initialization should always return DEFRAG_NOT_DONE
  1182	        }
  1183	
  1184	        doneStatus status = defrag.current_stage->stage_fn(endtime, defrag.current_stage->target, defrag.current_stage->privdata);
  1185	        if (status == DEFRAG_DONE) {
  1186	            zfree(defrag.current_stage);
  1187	            defrag.current_stage = NULL;
  1188	        }
  1189	
  1190	        haveMoreWork = (defrag.current_stage || listLength(defrag.remaining_stages) > 0);
  1191	        /* If we've completed a stage early, and still have a standard time allotment remaining,
  1192	         * we'll start another stage.  This can happen when defrag is running infrequently, and
  1193	         * starvation protection has increased the duty-cycle. */
  1194	    } while (haveMoreWork && getMonotonicUs() <= endtime - server.active_defrag_cycle_us);
  1195	
  1196	    latencyEndMonitor(latency);
  1197	    latencyAddSampleIfNeeded("active-defrag-cycle", latency);
  1198	    latencyTraceIfNeeded(db, active_defrag_cycle, latency);
  1199	    if (haveMoreWork) {
  1200	        return computeDelayMs(endtime);
  1201	    } else {
  1202	        endDefragCycle(true);
  1203	        return AE_NOMORE; // Ends the timer proc
  1204	    }
  1205	}
  1206	
  1207	
  1208	/* During long running scripts, or while loading, there is a periodic function for handling other
  1209	 * actions.  This interface allows defrag to continue running, avoiding a single long defrag step
  1210	 * after the long operation completes. */
  1211	void defragWhileBlocked(void) {
  1212	    // This is called infrequently, while timers are not active.  We might need to start defrag.
  1213	    if (!defragIsRunning()) monitorActiveDefrag();
  1214	
  1215	    if (!defragIsRunning()) return;
  1216	
  1217	    // Save off the timeproc_id.  If we have a normal termination, it will be cleared.
  1218	    long long timeproc_id = defrag.timeproc_id;
  1219	
  1220	    // Simulate a single call of the timer proc, allowing catch-up while timers are blocked.
  1221	    long long reschedule_delay = activeDefragTimeProc(NULL, 0, (void *)1);
  1222	    if (reschedule_delay == AE_NOMORE) {
  1223	        // If it's done, deregister the timer
  1224	        aeDeleteTimeEvent(server.el, timeproc_id);
  1225	    }

